#include <iostream>#include <string>#include <vector> using namespace std; int main() {    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int t;    cin >> t;    while (t--) {        int n;        cin >> n;        string s;        cin >> s;        vector<bool> visited(n, false);         int current_pos = 0;         visited[current_pos] = true;        for (int j = 0; j < n; j++) {            if (s[current_pos] == 'L') {                current_pos--;             } else {                current_pos++;             }            visited[current_pos] = true;         }         int count = 0;        for (int i = 0; i < n; i++) {            if (visited[i]) {                count++;            }        }        cout << count << "\n";    }    return 0;}